import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonArray;
import com.google.gson.JsonElement;
import org.junit.jupiter.api.Test;

class JsonElementTest {

  @Test
  void getAsJsonArray_whenIsJsonArrayTrue_returnsThisAsJsonArray() {
    JsonElement jsonElement = mock(JsonElement.class);
    when(jsonElement.isJsonArray()).thenReturn(true);
    when(jsonElement.toString()).thenReturn("JsonElementToString");

    // Cast is safe because isJsonArray returns true and we mock the cast
    when(jsonElement.getAsJsonArray()).thenCallRealMethod();

    // To simulate (JsonArray) this, mock jsonElement as JsonArray as well
    JsonArray jsonArray = mock(JsonArray.class);
    // Use Mockito's withSettings().extraInterfaces() to let jsonElement also be a JsonArray
    JsonElement jsonElementWithJsonArray = mock(JsonElement.class, withSettings().extraInterfaces(JsonArray.class));
    when(jsonElementWithJsonArray.isJsonArray()).thenReturn(true);
    when(jsonElementWithJsonArray.getAsJsonArray()).thenCallRealMethod();

    // Invocation on jsonElementWithJsonArray should return itself cast to JsonArray
    JsonArray result = jsonElementWithJsonArray.getAsJsonArray();
    assertNotNull(result);
    assertSame(jsonElementWithJsonArray, result);
  }

  @Test
  void getAsJsonArray_whenIsJsonArrayFalse_throwsIllegalStateException() {
    JsonElement jsonElement = mock(JsonElement.class);
    when(jsonElement.isJsonArray()).thenReturn(false);
    when(jsonElement.toString()).thenReturn("NotJsonArray");

    when(jsonElement.getAsJsonArray()).thenCallRealMethod();

    IllegalStateException exception = assertThrows(IllegalStateException.class, jsonElement::getAsJsonArray);
    assertEquals("Not a JSON Array: NotJsonArray", exception.getMessage());
  }
}
